import React, { useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import '../styles/Home.css';

function Home() {
  const navigate = useNavigate();

  useEffect(() => {
    // Перевіряємо, чи користувач вже авторизований
    const userId = localStorage.getItem('user_id');
    if (userId) {
      checkUserRole(userId);
    }
  }, [navigate]);

  // Функція для перевірки ролі користувача
  const checkUserRole = async (userId) => {
    try {
      const response = await fetch(`http://localhost:5000/api/user-role/${userId}`);
      if (!response.ok) {
        // Якщо помилка, просто показуємо головну сторінку
        return;
      }
      
      const data = await response.json();
      if (data.role === 'admin') {
        // Якщо адміністратор, перенаправляємо на адмін-панель
        navigate('/admin-dashboard');
      } else {
        // Якщо звичайний користувач, перенаправляємо на звичайну панель
        navigate('/dashboard');
      }
    } catch (err) {
      console.error('Error checking user role:', err);
      // При помилці залишаємо користувача на головній сторінці
    }
  };

  return (
    <div className="home-container">
      <div className="center-frame">
        <h1>Welcome to the Asthma Monitoring App</h1>
        <div className="button-container">
          <button 
            className="signup-button"
            onClick={() => navigate('/signup')}
          >
            Sign Up
          </button>
          <button 
            className="login-button"
            onClick={() => navigate('/login')}
          >
            Login
          </button>
        </div>
      </div>
    </div>
  );
}

export default Home;
